INSERT INTO esg.tb_approval_info( target_type, target_id, display_name, hr_id, param, signature, hr_nm, orgn_nm, jbrp_nm, created_at, created_by, type )
SELECT #{targetType}, #{targetId}, #{displayName}, thi.hr_id, #{param}, #{signature}, thi.hr_nm, toi.orgn_nm, jbrp.jbrp_nm, now(), #{userId}, #{type} FROM esg.tb_hr_info thi LEFT JOIN esg.tb_orgn_info toi ON thi.orgn_id = toi.orgn_id LEFT JOIN esg.tb_hr_info_jbrp jbrp ON jbrp.jbrp_id = thi.jbrp and jbrp.comp_id = #{compId} WHERE thi.hr_id = #{hrId}
SELECT #{targetType}, #{targetId}, #{displayName}, NULL, #{param}, #{signature}, NULL, NULL, NULL, now(), #{userId}, #{type}
RETURNING seq

