UPDATE esg.tb_approval_info tai
   SET updated_at = now(),
    updated_by = #{userId},


        hr_id = #{hrId},
        hr_nm = #{hrNm},
        orgn_nm = (
        SELECT toi.orgn_nm
        FROM esg.tb_hr_info thi
        LEFT JOIN esg.tb_orgn_info toi ON thi.orgn_id = toi.orgn_id
        WHERE thi.hr_id = #{hrId}
        ),
        jbrp_nm = (
        SELECT jbrp.jbrp_nm
        FROM esg.tb_hr_info thi
        LEFT JOIN esg.tb_hr_info_jbrp jbrp ON jbrp.jbrp_id = thi.jbrp and jbrp.comp_id = #{compId}
        WHERE thi.hr_id = #{hrId}
        ),
        signature = #{signature}


        hr_id = null,
        hr_nm = null,
        orgn_nm = null,
        jbrp_nm = null,
        signature = null


WHERE target_id = #{targetId}
  AND target_type = #{targetType}
  AND param = #{param}
  AND type = #{type}
  AND seq = #{seq}


        UPDATE esg.tb_approval_info tai
           SET signature = (select signature
							  from esg.tb_user_info tui 
							  join esg.tb_hr_info thi 
							    on tui.user_id = thi.user_id
							   and thi.hr_id = tai.hr_id ),
            updated_at = now(),
            updated_by = #{userId}
        WHERE target_id = #{targetId}
          AND target_type = #{targetType}
          AND param = #{param}
          AND type = #{type}
          AND seq = #{seq}


